const PiranhaMessage = require('../../PiranhaMessage')

class SectorHearbeatMessage extends PiranhaMessage {
  constructor (client) {
    super()
    this.id = 24109
    this.client = client
    this.version = 1
  }

  async encode () {
    this.writeHex('')
  }
}

module.exports = SectorHearbeatMessage